import React, { createContext, useState, useContext, useEffect } from 'react';
import api from '../services/api';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const token = localStorage.getItem('access_token');
        const storedUser = localStorage.getItem('user');
        if (token && storedUser) {
            setUser(JSON.parse(storedUser));
        }
        setLoading(false);
    }, []);

    const login = async (username, password, role) => {
        try {
            const response = await api.post('/auth/login', { username, password });
            const { access_token } = response.data.data;

            localStorage.setItem('access_token', access_token);
            localStorage.setItem('user', JSON.stringify({ username, role }));
            setUser({ username, role });
            return { success: true };
        } catch (err) {
            return { success: false, message: err.response?.data?.message || 'Login failed' };
        }
    };

    const logout = () => {
        localStorage.removeItem('access_token');
        localStorage.removeItem('user');
        setUser(null);
    };

    return (
        <AuthContext.Provider value={{ user, login, logout, loading }}>
            {children}
        </AuthContext.Provider>
    );
};

export const useAuth = () => useContext(AuthContext);

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
import './AdminDashboard.css';

const AdminDashboard = () => {
    const [claims, setClaims] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const navigate = useNavigate();

    const fetchClaims = async () => {
        try {
            setLoading(true);
            const response = await api.get('/admin/claims');
            setClaims(response.data.data.claims || response.data.data || []);
            setError(null);
        } catch (err) {
            if (err.response?.status === 403 || err.response?.status === 401) {
                navigate('/login'); // Not authorized or session expired
            } else {
                setError('Failed to fetch pending claims.');
            }
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchClaims();
    }, [navigate]);

    const verifyClaim = async (claimId, decision, notes = '') => {
        try {
            await api.post(`/admin/claims/${claimId}/verify`, { decision, handover_notes: notes });
            alert(`Claim ${decision} successfully`);
            fetchClaims(); // Refresh list
        } catch (err) {
            alert(`Error verifying claim: ${err.response?.data?.message || err.message}`);
        }
    };

    return (
        <div className="admin-dashboard">
            <h2 className="admin-title">Admin Dashboard: Pending Claims</h2>

            {loading ? (
                <div className="loading-spinner">Loading claims...</div>
            ) : error ? (
                <div className="error-message">{error}</div>
            ) : claims.length === 0 ? (
                <p className="no-items">No pending claims to review.</p>
            ) : (
                <div className="claims-list">
                    {claims.map((claim) => (
                        <div key={claim.id} className="claim-card glass-panel">
                            <div className="claim-header">
                                <h3>Claim #{claim.id}</h3>
                                <span className={`status-badge ${claim.status}`}>{claim.status}</span>
                            </div>
                            <div className="claim-body">
                                <p><strong>Item Name:</strong> {claim.item_name || `Found Item ID: ${claim.found_item_id}`}</p>
                                <p><strong>Claimant Email:</strong> {claim.claimant_email || 'N/A'}</p>
                                <p><strong>Reported Description:</strong> {claim.description}</p>
                                <p><strong>Declared Value:</strong> ${claim.declared_value}</p>
                                <p><strong>Match Score:</strong> <span className="score">{claim.score || 'N/A'}%</span></p>
                                {claim.receipt_proof && (
                                    <p><strong>Proof URL:</strong> <a href={claim.receipt_proof} target="_blank" rel="noreferrer">View Proof</a></p>
                                )}
                            </div>
                            <div className="claim-actions">
                                <button
                                    className="auth-primary-btn approve-btn"
                                    onClick={() => verifyClaim(claim.id, 'approved')}
                                >Approve</button>
                                <button
                                    className="auth-secondary-btn reject-btn"
                                    onClick={() => verifyClaim(claim.id, 'rejected')}
                                >Reject</button>
                                <button
                                    className="auth-secondary-btn complete-btn"
                                    onClick={() => verifyClaim(claim.id, 'completed', 'Handed over directly')}
                                >Complete Handover</button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
import './AdminDashboard.css';

const AdminReports = () => {
    const [reports, setReports] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const navigate = useNavigate();

    const fetchReports = async () => {
        try {
            setLoading(true);
            const response = await api.get('/admin/reports/transactions');
            setReports(response.data.data.transactions || response.data.data || []);
            setError(null);
        } catch (err) {
            if (err.response?.status === 403 || err.response?.status === 401) {
                navigate('/login');
            } else {
                setError('Failed to fetch transaction reports.');
            }
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReports();
    }, [navigate]);

    return (
        <div className="admin-dashboard">
            <h2 className="admin-title">Transaction Reports</h2>

            {loading ? (
                <div className="loading-spinner">Loading reports...</div>
            ) : error ? (
                <div className="error-message">{error}</div>
            ) : reports.length === 0 ? (
                <p className="no-items">No completed transactions found.</p>
            ) : (
                <div className="claims-list">
                    {reports.map((report) => (
                        <div key={report.claim_id} className="claim-card glass-panel">
                            <div className="claim-header">
                                <h3>Transaction #{report.claim_id}</h3>
                                <span className="status-badge completed">Completed</span>
                            </div>
                            <div className="claim-body">
                                <p><strong>Item Name:</strong> {report.item_name}</p>
                                <p><strong>Admin Username:</strong> {report.admin_username}</p>
                                <p><strong>Claimant Email:</strong> {report.claimant_email}</p>
                                <p><strong>Verification Details:</strong> {report.verification_details}</p>
                                <p><strong>Handover Timestamp:</strong> {new Date(report.transaction_timestamp).toLocaleString()}</p>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default AdminReports;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../services/api';
import './ItemDetail.css';

const ItemDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [item, setItem] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [showClaimForm, setShowClaimForm] = useState(false);
    const [claimData, setClaimData] = useState({
        description: '',
        declared_value: '',
        receipt_proof: ''
    });

    useEffect(() => {
        // Since we don't have a single item endpoint in spec yet, we'll fetch list and find, or assume a new endpoint
        const fetchItem = async () => {
            try {
                setLoading(true);
                // Assuming we could pass full item via state, or we fetch from search 
                // For robustness, simulating a fetch by getting found items and filtering
                const response = await api.get('/items/found', { params: { limit: 100 } });
                const items = response.data.data.items || [];
                const foundItem = items.find(i => i.id === parseInt(id));

                if (foundItem) {
                    setItem(foundItem);
                } else {
                    setError('Item not found.');
                }
            } catch (err) {
                setError('Failed to fetch item details.');
            } finally {
                setLoading(false);
            }
        };
        fetchItem();
    }, [id]);

    const handleClaimSubmit = async (e) => {
        e.preventDefault();
        try {
            await api.post('/claims/submit', {
                found_item_id: item.id,
                ...claimData,
                declared_value: parseFloat(claimData.declared_value)
            });
            alert('Claim submitted successfully!');
            navigate('/lost-items');
        } catch (err) {
            alert(err.response?.data?.message || 'Failed to submit claim.');
        }
    };

    if (loading) return <div className="loading-spinner">Loading...</div>;
    if (error) return <div className="error-message">{error}</div>;
    if (!item) return null;

    return (
        <div className="item-detail-page">
            <button className="back-btn" onClick={() => navigate(-1)}>ΓåÉ Back</button>

            <div className="item-detail-container glass-panel">
                <div className="item-detail-image">
                    <img src={item.image_url || 'https://via.placeholder.com/600x400?text=No+Image'} alt={item.item_type} />
                </div>

                <div className="item-detail-info">
                    <h2>{item.item_type}</h2>
                    <div className="info-grid">
                        <div className="info-item"><span>Category:</span> {item.category}</div>
                        <div className="info-item"><span>Color:</span> {item.color}</div>
                        <div className="info-item"><span>Brand:</span> {item.brand || 'N/A'}</div>
                        <div className="info-item"><span>Location Found:</span> {item.found_location}</div>
                        <div className="info-item"><span>Date Found:</span> {new Date(item.found_datetime || item.created_at).toLocaleDateString()}</div>
                    </div>
                    <div className="info-description">
                        <h3>Description</h3>
                        <p>{item.public_description || item.full_description || 'No description provided.'}</p>
                    </div>

                    {!showClaimForm ? (
                        <button className="claim-btn" onClick={() => setShowClaimForm(true)}>
                            Claim This Item
                        </button>
                    ) : (
                        <form className="claim-form" onSubmit={handleClaimSubmit}>
                            <h3>Submit Claim</h3>
                            <div className="form-group">
                                <label>Proof Description (How do we know it's yours?)</label>
                                <textarea
                                    required
                                    className="auth-input"
                                    value={claimData.description}
                                    onChange={e => setClaimData({ ...claimData, description: e.target.value })}
                                />
                            </div>
                            <div className="form-group">
                                <label>Declared Value ($)</label>
                                <input
                                    type="number"
                                    step="0.01"
                                    required
                                    className="auth-input"
                                    value={claimData.declared_value}
                                    onChange={e => setClaimData({ ...claimData, declared_value: e.target.value })}
                                />
                            </div>
                            <div className="form-group">
                                <label>Receipt or Proof URL</label>
                                <input
                                    type="text"
                                    required
                                    className="auth-input"
                                    value={claimData.receipt_proof}
                                    onChange={e => setClaimData({ ...claimData, receipt_proof: e.target.value })}
                                />
                            </div>
                            <div className="form-actions">
                                <button type="submit" className="auth-primary-btn">Submit Claim</button>
                                <button type="button" className="auth-secondary-btn" onClick={() => setShowClaimForm(false)}>Cancel</button>
                            </div>
                        </form>
                    )}
                </div>
            </div>
        </div>
    );
};

export default ItemDetail;

import React, { useState, useEffect } from 'react';
import ItemCard from '../../components/UI/ItemCard';
import SearchBar from '../../components/UI/SearchBar';
import api from '../../services/api';

const ReturnedItems = () => {
    const [items, setItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const fetchItems = async (query = '', filter = '') => {
        try {
            setLoading(true);
            // For now, we use the same items/found endpoint but we'll eventually filter by 'returned' status
            // Once the backend supports a specific returned items endpoint, we will update this.
            // Currently, 'returned' items are just those with a completed handover/claim status.
            const response = await api.get('/items/found', {
                params: {
                    query,
                    status: 'completed' // Assuming the backend filters by status
                }
            });
            setItems(response.data.data.items || []);
            setError(null);
        } catch (err) {
            setError('Failed to fetch returned items.');
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchItems();
    }, []);

    return (
        <div className="returned-items-page">
            <SearchBar
                onSearch={(q) => fetchItems(q)}
                onFilter={(f) => fetchItems('', f)}
            />

            {loading ? (
                <div className="loading-spinner">Loading...</div>
            ) : error ? (
                <div className="error-message">{error}</div>
            ) : (
                <div className="items-grid">
                    {items.map(item => (
                        <ItemCard key={item.id} item={item} isReturned={true} />
                    ))}
                    {items.length === 0 && <p className="no-items">No returned items to display.</p>}
                </div>
            )}
        </div>
    );
};

export default ReturnedItems;
